+/**
+ * Analytics data models for the dashboard API.
+ *
+ * These interfaces define the contract for analytics data flowing through
+ * the system. The AnalyticsService will aggregate data from OrderRepository
+ * and UserRepository into these shapes.
+ *
+ * Design notes for implementers:
+ * - All date ranges use ISO 8601 strings at the API boundary, Date objects internally
+ * - TimeSeriesPoint granularity is determined by the requested time range
+ * - MetricSummary.changePercent is relative to the previous period of equal length
+ */
+
+import type { OrderStatus } from './order.js';
+
+// ---------------------------------------------------------------------------
+// Core analytics primitives
+// ---------------------------------------------------------------------------
+
+/**
+ * A single data point in a time series.
+ * Used for charting order volume, revenue, user signups over time.
+ */
+export interface TimeSeriesPoint {
+  /** ISO 8601 timestamp for the start of this bucket */
+  timestamp: string;
+  /** Numeric value for this bucket */
+  value: number;
+  /** Optional label (e.g., "Mon", "Week 12") */
+  label?: string;
+}
+
+/**
+ * Granularity for time-series aggregation.
+ * The API picks a sensible default based on the date range if omitted.
+ */
+export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';
+
+/**
+ * A single metric with its current value, trend, and comparison to prior period.
+ */
+export interface MetricSummary {
+  /** Machine-readable metric key (e.g., "total_revenue") */
+  name: string;
+  /** Human-readable display label */
+  label: string;
+  /** Current period value */
+  value: number;
+  /** Value from the previous period of equal length */
+  previousValue: number;
+  /** Percentage change from previous period: ((value - previousValue) / previousValue) * 100 */
+  changePercent: number;
+  /** Direction of change for quick UI rendering */
+  trend: 'up' | 'down' | 'flat';
+}
+
+// ---------------------------------------------------------------------------
+// Order analytics
+// ---------------------------------------------------------------------------
+
+/**
+ * Breakdown of orders by status for the given time range.
+ */
+export interface OrderStatusBreakdown {
+  status: OrderStatus;
+  count: number;
+  /** Revenue sum for orders in this status */
+  revenue: number;
+}
+
+/**
+ * Top-selling product derived from order items.
+ */
+export interface TopProduct {
+  productId: string;
+  name: string;
+  totalQuantity: number;
+  totalRevenue: number;
+}
+
+// ---------------------------------------------------------------------------
+// Dashboard aggregate
+// ---------------------------------------------------------------------------
+
+/**
+ * Full dashboard payload — the primary response for GET /api/analytics/dashboard.
+ * Combines KPI summaries, time-series data, and breakdowns in one response
+ * to minimize round-trips for the dashboard UI.
+ */
+export interface DashboardData {
+  /** Period these metrics cover */
+  dateRange: DateRange;
+
+  /** Key performance indicators shown as top-line cards */
+  kpis: {
+    totalOrders: MetricSummary;
+    totalRevenue: MetricSummary;
+    averageOrderValue: MetricSummary;
+    totalUsers: MetricSummary;
+  };
+
+  /** Order volume over time for the primary chart */
+  orderTimeSeries: TimeSeriesPoint[];
+
+  /** Revenue over time for the primary chart */
+  revenueTimeSeries: TimeSeriesPoint[];
+
+  /** Orders grouped by current status */
+  ordersByStatus: OrderStatusBreakdown[];
+
+  /** Top products by revenue in the period */
+  topProducts: TopProduct[];
+}
+
+// ---------------------------------------------------------------------------
+// Request / query types
+// ---------------------------------------------------------------------------
+
+/** ISO 8601 date range filter, used across all analytics endpoints. */
+export interface DateRange {
+  /** Inclusive start (ISO 8601) */
+  from: string;
+  /** Inclusive end (ISO 8601) */
+  to: string;
+}
+
+/**
+ * Supported metric type keys for the GET /api/analytics/metrics/:type endpoint.
+ */
+export type MetricType =
+  | 'orders'
+  | 'revenue'
+  | 'users'
+  | 'average-order-value';
+
+/**
+ * Query parameters common to analytics endpoints.
+ */
+export interface AnalyticsQuery {
+  from: string;
+  to: string;
+  granularity?: TimeGranularity;
+}
+
+/**
+ * Response shape for the single-metric time-series endpoint.
+ */
+export interface MetricTimeSeriesResponse {
+  metric: MetricType;
+  dateRange: DateRange;
+  granularity: TimeGranularity;
+  summary: MetricSummary;
+  series: TimeSeriesPoint[];
+}

