+/**
+ * Analytics aggregation service.
+ *
+ * Reads from OrderRepository and UserRepository to compute dashboard metrics.
+ * Does NOT write data — this is a read-only aggregation layer.
+ *
+ * ## Implementation guide for downstream developers
+ *
+ * 1. **getDashboard(query)** — The main entry point. Should:
+ *    - Fetch all orders and users within the date range
+ *    - Compute KPI MetricSummaries by comparing current vs. previous period
+ *    - Build time-series arrays bucketed by the resolved granularity
+ *    - Aggregate order-status breakdown and top-products list
+ *    - Return a complete DashboardData object
+ *
+ * 2. **getMetricTimeSeries(type, query)** — Single-metric deep dive:
+ *    - Resolve granularity (use resolveGranularity helper)
+ *    - Build the time-series for just the requested metric
+ *    - Compute the MetricSummary for the header card
+ *
+ * 3. **Granularity resolution** — If the caller doesn't specify granularity:
+ *    - <= 2 days  → 'hour'
+ *    - <= 30 days → 'day'
+ *    - <= 90 days → 'week'
+ *    - > 90 days  → 'month'
+ *
+ * 4. **Previous period comparison** — For a range of N days, the "previous period"
+ *    is the N days immediately before `from`. This is used to compute changePercent
+ *    and trend direction on MetricSummary.
+ */
+
+import type { OrderRepository } from '../repositories/order.repository.js';
+import type { UserRepository } from '../repositories/user.repository.js';
+import type {
+  AnalyticsQuery,
+  DashboardData,
+  DateRange,
+  MetricSummary,
+  MetricTimeSeriesResponse,
+  MetricType,
+  TimeGranularity,
+  TimeSeriesPoint,
+  OrderStatusBreakdown,
+  TopProduct,
+} from '../models/analytics.js';
+import { Logger } from '../utils/logger.js';
+
+/**
+ * Resolve granularity from the date range when not explicitly provided.
+ */
+export function resolveGranularity(from: string, to: string, explicit?: TimeGranularity): TimeGranularity {
+  if (explicit) return explicit;
+
+  const diffMs = new Date(to).getTime() - new Date(from).getTime();
+  const diffDays = diffMs / (1000 * 60 * 60 * 24);
+
+  if (diffDays <= 2) return 'hour';
+  if (diffDays <= 30) return 'day';
+  if (diffDays <= 90) return 'week';
+  return 'month';
+}
+
+/**
+ * Compute the previous period date range of equal length, ending just before `from`.
+ */
+export function previousPeriod(dateRange: DateRange): DateRange {
+  const fromMs = new Date(dateRange.from).getTime();
+  const toMs = new Date(dateRange.to).getTime();
+  const durationMs = toMs - fromMs;
+
+  return {
+    from: new Date(fromMs - durationMs).toISOString(),
+    to: new Date(fromMs).toISOString(),
+  };
+}
+
+/**
+ * Build a MetricSummary from current and previous values.
+ */
+export function buildMetricSummary(
+  name: string,
+  label: string,
+  value: number,
+  previousValue: number,
+): MetricSummary {
+  const changePercent =
+    previousValue === 0 ? (value > 0 ? 100 : 0) : ((value - previousValue) / previousValue) * 100;
+
+  const trend: MetricSummary['trend'] =
+    changePercent > 0.5 ? 'up' : changePercent < -0.5 ? 'down' : 'flat';
+
+  return { name, label, value, previousValue, changePercent, trend };
+}
+
+export class AnalyticsService {
+  private logger = new Logger('AnalyticsService');
+
+  constructor(
+    private orderRepository: OrderRepository,
+    private userRepository: UserRepository,
+  ) {}
+
+  /**
+   * Get the full dashboard payload.
+   *
+   * TODO: Implement aggregation logic. Currently returns placeholder data
+   * so that the route handlers compile and return a valid shape.
+   */
+  getDashboard(query: AnalyticsQuery): DashboardData {
+    this.logger.info(`Building dashboard for ${query.from} to ${query.to}`);
+
+    const dateRange: DateRange = { from: query.from, to: query.to };
+    const _granularity = resolveGranularity(query.from, query.to, query.granularity);
+
+    // --- Placeholder data — replace with real aggregation ---
+    const placeholderSummary = (name: string, label: string): MetricSummary =>
+      buildMetricSummary(name, label, 0, 0);
+
+    const placeholderSeries: TimeSeriesPoint[] = [];
+    const placeholderStatusBreakdown: OrderStatusBreakdown[] = [];
+    const placeholderTopProducts: TopProduct[] = [];
+
+    return {
+      dateRange,
+      kpis: {
+        totalOrders: placeholderSummary('total_orders', 'Total Orders'),
+        totalRevenue: placeholderSummary('total_revenue', 'Total Revenue'),
+        averageOrderValue: placeholderSummary('avg_order_value', 'Avg Order Value'),
+        totalUsers: placeholderSummary('total_users', 'Total Users'),
+      },
+      orderTimeSeries: placeholderSeries,
+      revenueTimeSeries: placeholderSeries,
+      ordersByStatus: placeholderStatusBreakdown,
+      topProducts: placeholderTopProducts,
+    };
+  }
+
+  /**
+   * Get a time-series breakdown for a single metric type.
+   *
+   * TODO: Implement per-metric aggregation. Currently returns placeholder data.
+   */
+  getMetricTimeSeries(type: MetricType, query: AnalyticsQuery): MetricTimeSeriesResponse {
+    this.logger.info(`Building ${type} time series for ${query.from} to ${query.to}`);
+
+    const dateRange: DateRange = { from: query.from, to: query.to };
+    const granularity = resolveGranularity(query.from, query.to, query.granularity);
+
+    return {
+      metric: type,
+      dateRange,
+      granularity,
+      summary: buildMetricSummary(type, type, 0, 0),
+      series: [],
+    };
+  }
+}

