/**
 * Analytics data models for the dashboard API.
 *
 * These types define the shape of analytics data flowing through the system.
 * The analytics service aggregates raw Order and User data into these
 * structures for dashboard consumption.
 *
 * Design notes for implementers:
 * - TimeSeriesPoint is the atomic unit — all time-based charts use it.
 * - MetricSummary wraps a single KPI with its trend data.
 * - DashboardData is the top-level composite returned by the dashboard endpoint.
 * - All date ranges use ISO 8601 strings at the API boundary, Date objects internally.
 */

// ---------------------------------------------------------------------------
// Time series
// ---------------------------------------------------------------------------

/**
 * A single data point in a time series.
 * Used for line charts, bar charts, and sparklines.
 */
export interface TimeSeriesPoint {
  /** ISO 8601 timestamp for this data point */
  timestamp: string;
  /** Numeric value at this point in time */
  value: number;
  /** Optional label (e.g., "Monday", "Week 12") */
  label?: string;
}

// ---------------------------------------------------------------------------
// Metrics
// ---------------------------------------------------------------------------

/** The metric types the analytics service can compute. */
export type MetricType =
  | 'total-orders'
  | 'total-revenue'
  | 'active-users'
  | 'average-order-value'
  | 'order-completion-rate';

/**
 * Summary of a single metric, including current value, previous-period
 * comparison, and an optional time series for trend visualization.
 */
export interface MetricSummary {
  type: MetricType;
  /** Human-readable metric name */
  label: string;
  /** Current period value */
  currentValue: number;
  /** Previous period value (for delta calculation) */
  previousValue: number;
  /** Percentage change from previous to current period */
  changePercent: number;
  /** Direction of the trend */
  trend: 'up' | 'down' | 'flat';
  /** Time series data points for this metric (optional, included when detail requested) */
  series?: TimeSeriesPoint[];
}

// ---------------------------------------------------------------------------
// Order analytics
// ---------------------------------------------------------------------------

/**
 * Breakdown of orders by their current status.
 */
export interface OrderStatusBreakdown {
  pending: number;
  confirmed: number;
  shipped: number;
  delivered: number;
  cancelled: number;
}

// ---------------------------------------------------------------------------
// Dashboard composite
// ---------------------------------------------------------------------------

/**
 * Top-level response shape for GET /api/analytics/dashboard.
 * Combines all metric summaries and breakdowns into a single payload
 * so the frontend can render the full dashboard in one request.
 */
export interface DashboardData {
  /** Period these analytics cover */
  period: DateRange;
  /** Key performance indicators */
  metrics: MetricSummary[];
  /** Order count by status */
  ordersByStatus: OrderStatusBreakdown;
  /** Revenue over time for the period */
  revenueTimeSeries: TimeSeriesPoint[];
  /** Orders over time for the period */
  ordersTimeSeries: TimeSeriesPoint[];
  /** Timestamp when this data was computed */
  generatedAt: string;
}

// ---------------------------------------------------------------------------
// Query parameters
// ---------------------------------------------------------------------------

/** Granularity for time series aggregation. */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Date range for analytics queries.
 */
export interface DateRange {
  /** Start of the range (inclusive), ISO 8601 */
  from: string;
  /** End of the range (inclusive), ISO 8601 */
  to: string;
}

/**
 * Query parameters accepted by analytics endpoints.
 */
export interface AnalyticsQuery {
  /** Date range to analyze */
  dateRange: DateRange;
  /** Time series granularity */
  granularity: TimeGranularity;
  /** Optional user ID to scope analytics to a single user */
  userId?: string;
}

// ---------------------------------------------------------------------------
// Route handler types (framework-agnostic)
// ---------------------------------------------------------------------------

/**
 * Generic request shape for analytics route handlers.
 * Framework adapters (Express, Fastify, etc.) map their native
 * request objects into this shape before calling the handler.
 */
export interface AnalyticsRequest<TParams = Record<string, string>> {
  query: AnalyticsQuery;
  params: TParams;
}

/**
 * Generic response shape returned by analytics route handlers.
 */
export interface AnalyticsResponse<TData> {
  success: boolean;
  data: TData;
  error?: string;
}

/**
 * Analytics data models for the dashboard API.
 *
 * These interfaces define the contract for analytics data flowing through
 * the system. The analytics service aggregates data from Orders and Users
 * into these shapes for dashboard consumption.
 *
 * Design notes for implementers:
 * - TimeSeriesPoint is the atomic unit — all time-based charts use it.
 * - MetricSummary wraps a single KPI with trend data.
 * - DashboardData is the top-level response combining all widgets.
 * - All date ranges use ISO 8601 strings in request params, Date objects internally.
 */

// ---------------------------------------------------------------------------
// Core types
// ---------------------------------------------------------------------------

/**
 * A single point in a time series (e.g., revenue per day).
 */
export interface TimeSeriesPoint {
  timestamp: Date;
  value: number;
  label?: string;
}

/**
 * Granularity for time-series aggregation.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Supported metric types for the GET /metrics/:type endpoint.
 */
export type MetricType =
  | 'revenue'
  | 'orders'
  | 'average-order-value'
  | 'users'
  | 'conversion-rate';

/**
 * Direction of a trend compared to the previous period.
 */
export type TrendDirection = 'up' | 'down' | 'flat';

// ---------------------------------------------------------------------------
// Response shapes
// ---------------------------------------------------------------------------

/**
 * Summary of a single KPI metric, including comparison to prior period.
 */
export interface MetricSummary {
  type: MetricType;
  /** Current period value (e.g., total revenue this week). */
  currentValue: number;
  /** Previous period value for comparison. */
  previousValue: number;
  /** Percentage change from previous to current period. */
  changePercent: number;
  trend: TrendDirection;
  /** Time-series breakdown within the requested range. */
  series: TimeSeriesPoint[];
}

/**
 * Breakdown of orders by status — used for the status distribution widget.
 */
export interface OrderStatusBreakdown {
  status: string;
  count: number;
  percentage: number;
}

/**
 * A single row in the "top users" leaderboard widget.
 */
export interface TopUser {
  userId: string;
  userName: string;
  totalOrders: number;
  totalSpent: number;
}

/**
 * Full dashboard payload returned by GET /api/analytics/dashboard.
 * Combines all widget data into one response so the frontend can
 * render the dashboard with a single request.
 */
export interface DashboardData {
  /** High-level KPI cards (revenue, orders, users, etc.). */
  metrics: MetricSummary[];
  /** Order counts grouped by status. */
  ordersByStatus: OrderStatusBreakdown[];
  /** Top users by total spend. */
  topUsers: TopUser[];
  /** When this snapshot was generated. */
  generatedAt: Date;
}

// ---------------------------------------------------------------------------
// Request / query parameter shapes
// ---------------------------------------------------------------------------

/**
 * Query parameters accepted by dashboard and metric endpoints.
 */
export interface AnalyticsQuery {
  /** Start of the date range (inclusive). */
  startDate: Date;
  /** End of the date range (inclusive). */
  endDate: Date;
  /** Aggregation granularity for time-series data. */
  granularity: TimeGranularity;
}

/**
 * Parameters for the GET /api/analytics/metrics/:type endpoint.
 */
export interface MetricQuery extends AnalyticsQuery {
  type: MetricType;
}

/**
 * Analytics data models for the dashboard API.
 *
 * These interfaces define the contract for analytics data flowing through
 * the system. The AnalyticsService will aggregate data from OrderRepository
 * and UserRepository into these shapes.
 *
 * Design notes for implementers:
 * - All date ranges use ISO 8601 strings at the API boundary, Date objects internally
 * - TimeSeriesPoint granularity is determined by the requested time range
 * - MetricSummary.changePercent is relative to the previous period of equal length
 */

import type { OrderStatus } from './order.js';

// ---------------------------------------------------------------------------
// Core analytics primitives
// ---------------------------------------------------------------------------

/**
 * A single data point in a time series.
 * Used for charting order volume, revenue, user signups over time.
 */
export interface TimeSeriesPoint {
  /** ISO 8601 timestamp for the start of this bucket */
  timestamp: string;
  /** Numeric value for this bucket */
  value: number;
  /** Optional label (e.g., "Mon", "Week 12") */
  label?: string;
}

/**
 * Granularity for time-series aggregation.
 * The API picks a sensible default based on the date range if omitted.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * A single metric with its current value, trend, and comparison to prior period.
 */
export interface MetricSummary {
  /** Machine-readable metric key (e.g., "total_revenue") */
  name: string;
  /** Human-readable display label */
  label: string;
  /** Current period value */
  value: number;
  /** Value from the previous period of equal length */
  previousValue: number;
  /** Percentage change from previous period: ((value - previousValue) / previousValue) * 100 */
  changePercent: number;
  /** Direction of change for quick UI rendering */
  trend: 'up' | 'down' | 'flat';
}

// ---------------------------------------------------------------------------
// Order analytics
// ---------------------------------------------------------------------------

/**
 * Breakdown of orders by status for the given time range.
 */
export interface OrderStatusBreakdown {
  status: OrderStatus;
  count: number;
  /** Revenue sum for orders in this status */
  revenue: number;
}

/**
 * Top-selling product derived from order items.
 */
export interface TopProduct {
  productId: string;
  name: string;
  totalQuantity: number;
  totalRevenue: number;
}

// ---------------------------------------------------------------------------
// Dashboard aggregate
// ---------------------------------------------------------------------------

/**
 * Full dashboard payload — the primary response for GET /api/analytics/dashboard.
 * Combines KPI summaries, time-series data, and breakdowns in one response
 * to minimize round-trips for the dashboard UI.
 */
export interface DashboardData {
  /** Period these metrics cover */
  dateRange: DateRange;

  /** Key performance indicators shown as top-line cards */
  kpis: {
    totalOrders: MetricSummary;
    totalRevenue: MetricSummary;
    averageOrderValue: MetricSummary;
    totalUsers: MetricSummary;
  };

  /** Order volume over time for the primary chart */
  orderTimeSeries: TimeSeriesPoint[];

  /** Revenue over time for the primary chart */
  revenueTimeSeries: TimeSeriesPoint[];

  /** Orders grouped by current status */
  ordersByStatus: OrderStatusBreakdown[];

  /** Top products by revenue in the period */
  topProducts: TopProduct[];
}

