/**
 * Analytics route handlers (framework-agnostic).
 *
 * These handlers receive parsed request data and return typed response objects.
 * They are intentionally decoupled from any HTTP framework (Express, Fastify, etc.)
 * so that consumers can wire them into their server of choice.
 *
 * ## Route map
 *
 * | Method | Path                           | Handler              | Description                          |
 * |--------|--------------------------------|----------------------|--------------------------------------|
 * | GET    | /api/analytics/dashboard       | handleGetDashboard   | Full dashboard with KPIs & charts    |
 * | GET    | /api/analytics/metrics/:type   | handleGetMetric      | Single metric time-series deep dive  |
 * | GET    | /api/analytics/top-products    | handleGetTopProducts | Top products by revenue              |
 *
 * ## Query parameters (all endpoints)
 *
 * | Param       | Type            | Required | Default               |
 * |-------------|-----------------|----------|-----------------------|
 * | from        | ISO 8601 string | yes      | —                     |
 * | to          | ISO 8601 string | yes      | —                     |
 * | granularity | TimeGranularity | no       | auto from date range  |
 *
 * ## Usage example (Express)
 *
 * ```ts
 * import { createAnalyticsHandlers } from './routes/analytics.routes.js';
 *
 * const handlers = createAnalyticsHandlers(analyticsService);
 * app.get('/api/analytics/dashboard', (req, res) => {
 *   const result = handlers.handleGetDashboard({
 *     from: req.query.from as string,
 *     to: req.query.to as string,
 *     granularity: req.query.granularity as TimeGranularity | undefined,
 *   });
 *   res.json(result);
 * });
 * ```
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type {
  AnalyticsQuery,
  DashboardData,
  MetricTimeSeriesResponse,
  MetricType,
  TopProduct,
  TimeGranularity,
} from '../models/analytics.js';

// ---------------------------------------------------------------------------
// Validation helpers
// ---------------------------------------------------------------------------

const VALID_METRIC_TYPES: MetricType[] = ['orders', 'revenue', 'users', 'average-order-value'];

function isValidMetricType(type: string): type is MetricType {
  return (VALID_METRIC_TYPES as string[]).includes(type);
}

function isValidISODate(value: string): boolean {
  return !isNaN(Date.parse(value));
}

function validateAnalyticsQuery(params: Record<string, unknown>): AnalyticsQuery {
  const from = params['from'];
  const to = params['to'];

  if (typeof from !== 'string' || !isValidISODate(from)) {
    throw new AnalyticsValidationError('"from" must be a valid ISO 8601 date string');
  }
  if (typeof to !== 'string' || !isValidISODate(to)) {
    throw new AnalyticsValidationError('"to" must be a valid ISO 8601 date string');
  }
  if (new Date(from) >= new Date(to)) {
    throw new AnalyticsValidationError('"from" must be before "to"');
  }

  const granularity = params['granularity'] as TimeGranularity | undefined;
  if (granularity !== undefined && !['hour', 'day', 'week', 'month'].includes(granularity)) {
    throw new AnalyticsValidationError(
      `Invalid granularity "${granularity}". Must be one of: hour, day, week, month`,
    );
  }

  return { from, to, granularity };
}

// ---------------------------------------------------------------------------
// Error types
// ---------------------------------------------------------------------------

export class AnalyticsValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'AnalyticsValidationError';
  }
}

// ---------------------------------------------------------------------------
// Handler factory
// ---------------------------------------------------------------------------

export interface AnalyticsHandlers {
  /** GET /api/analytics/dashboard?from=...&to=...&granularity=... */
  handleGetDashboard(params: Record<string, unknown>): DashboardData;

  /** GET /api/analytics/metrics/:type?from=...&to=...&granularity=... */
  handleGetMetric(type: string, params: Record<string, unknown>): MetricTimeSeriesResponse;

  /** GET /api/analytics/top-products?from=...&to=... */
  handleGetTopProducts(params: Record<string, unknown>): TopProduct[];
}

/**
 * Create analytics route handlers bound to an AnalyticsService instance.
 *
 * This factory follows the same dependency-injection pattern used by the
 * existing services (constructor injection) but adapted for a handler layer.
 */
export function createAnalyticsHandlers(analyticsService: AnalyticsService): AnalyticsHandlers {
  return {
    handleGetDashboard(params: Record<string, unknown>): DashboardData {
      const query = validateAnalyticsQuery(params);
      return analyticsService.getDashboard(query);
    },

    handleGetMetric(type: string, params: Record<string, unknown>): MetricTimeSeriesResponse {
      if (!isValidMetricType(type)) {
        throw new AnalyticsValidationError(
          `Invalid metric type "${type}". Must be one of: ${VALID_METRIC_TYPES.join(', ')}`,
        );
      }
      const query = validateAnalyticsQuery(params);
      return analyticsService.getMetricTimeSeries(type, query);
    },

    handleGetTopProducts(params: Record<string, unknown>): TopProduct[] {
      const query = validateAnalyticsQuery(params);
      const dashboard = analyticsService.getDashboard(query);
      return dashboard.topProducts;
    },
  };
}
